    double minTime(int n, int k, int m, vector<int>& time, vector<double>& mul) {
        priority_queue<int, vector<int>, greater<int>> pq(time.begin(), time.end());
        double totalTime = 0;
        int currentStage = 0;
        while (n > 0) {
            vector<int> group;
            for (int i = 0; i < k && n > 0; ++i) {
                group.push_back(pq.top());
                pq.pop();
                --n;
            }
            double crossingTime = *max_element(group.begin(), group.end()) * mul[currentStage];
            totalTime += crossingTime;
            currentStage = (currentStage + floor(crossingTime)) % m;
            if (group.size() < k) {
                int returnTime = time[group.back()] * mul[currentStage];
                totalTime += returnTime;
                currentStage = (currentStage + floor(returnTime)) % m;
            }
        }
        return totalTime;
    }
};
